sys_script_email.script:
if (current.item_type == "cmdb_ci_computer") {
    var request = new sn_ws.RESTMessageV2();
    request.setEndpoint('https://dev201361.service-now.com/api/now/table/u_password_vault?sysparm_query=u_asset%3D' + current.cmdb_ci.asset_tag + '&sysparm_fields=u_password&sysparm_limit=1');
    request.setHttpMethod('GET');
    var user = 'admin';
    var password = 'dev201361'; 
    request.setBasicAuth(user, password);
    request.setRequestHeader("Accept", "application/json");
    var response = request.execute();
    var obj = JSON.parse(response.getBody());

    if (obj.result && obj.result.length > 0) {
        var myPass = obj.result[0].u_password;
        template.print('The admin password for your laptop is: ' + myPass);
    } else {
        template.print('No password found for asset ' + current.cmdb_ci.asset_tag);
    }
}
